import{_ as i,c as r,o,ah as a}from"./chunks/framework.Cnj7lwEt.js";const d=JSON.parse('{"title":"💻 编程语言","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/编程语言/index.md","filePath":"github汇总/编程语言/index.md"}'),t={name:"github汇总/编程语言/index.md"};function n(e,l,s,g,h,u){return o(),r("div",null,l[0]||(l[0]=[a('<h1 id="💻-编程语言" tabindex="-1">💻 编程语言 <a class="header-anchor" href="#💻-编程语言" aria-label="Permalink to “💻 编程语言”">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to “概述”">​</a></h2><p>编程语言是软件开发的基石，不同的编程语言适用于不同的场景和需求。本分类汇集了各类优质的编程语言，包括现代系统编程语言、函数式编程语言、AI专用语言等，帮助您选择合适的语言进行开发。</p><h2 id="语言列表" tabindex="-1">语言列表 <a class="header-anchor" href="#语言列表" aria-label="Permalink to “语言列表”">​</a></h2><h3 id="gleam" tabindex="-1">Gleam <a class="header-anchor" href="#gleam" aria-label="Permalink to “Gleam”">​</a></h3><ul><li><strong>项目名称</strong>: Gleam</li><li><strong>作者</strong>: gleam-lang</li><li><strong>核心功能</strong>: 类型安全的函数式编程语言，用于构建可扩展的并发系统，可编译到 Erlang 虚拟机或 JavaScript</li><li><strong>主要亮点</strong>: <ul><li>类型安全，编译时即可发现大量错误</li><li>函数式编程特性，代码简洁易维护</li><li>并发处理优雅，适合构建高并发系统</li><li>可编译到 Erlang 虚拟机或 JavaScript，跨平台支持</li><li>学习曲线友好，适合函数式编程新手和老手</li></ul></li><li><strong>详细介绍</strong>: <a href="/github汇总/编程语言/Gleam-编程语言.html">Gleam 完整文档</a></li><li><strong>GitHub 地址</strong>: <a href="https://github.com/gleam-lang/gleam" target="_blank" rel="noreferrer">https://github.com/gleam-lang/gleam</a></li></ul><hr><h3 id="go" tabindex="-1">Go <a class="header-anchor" href="#go" aria-label="Permalink to “Go”">​</a></h3><ul><li><strong>项目名称</strong>: Go</li><li><strong>作者</strong>: The Go Authors</li><li><strong>核心功能</strong>: 简洁易读的语法，超快的编译速度，内置强大的并发编程支持，跨平台编译，标准库丰富</li><li><strong>主要亮点</strong>: <ul><li>由谷歌主导开发，数千名社区开发者共同贡献</li><li>完全开源免费，无 vendor lock-in</li><li>语法简洁，代码可读性高</li><li>编译速度极快，开发体验流畅</li><li>内置并发模型，轻松构建高性能应用</li><li>云原生应用开发的主流选择</li></ul></li><li><strong>详细介绍</strong>: <a href="/github汇总/编程语言/Go-编程语言.html">Go 完整文档</a></li><li><strong>GitHub 地址</strong>: <a href="https://github.com/golang/go" target="_blank" rel="noreferrer">https://github.com/golang/go</a></li></ul><hr><h3 id="inkos" tabindex="-1">inkos <a class="header-anchor" href="#inkos" aria-label="Permalink to “inkos”">​</a></h3><ul><li><strong>项目名称</strong>: inkos</li><li><strong>作者</strong>: Narcooo</li><li><strong>核心功能</strong>: 受 Rust 和 Lua 影响的小语言，与 Lua 运行时兼容，可编译为 Lua 源代码</li><li><strong>主要亮点</strong>: <ul><li>提供比 Lua 更安全、更强大的语言选择</li><li>保持 Lua 的灵活性和简洁性</li><li>为喜欢 Rust 安全特性但需要 Lua 脚本便利性的开发者提供折中方案</li><li>可以利用现有的 Lua 生态系统</li></ul></li><li><strong>详细介绍</strong>: <a href="/github汇总/编程语言/inkos-编程语言.html">inkos 完整文档</a></li><li><strong>GitHub 地址</strong>: <a href="https://github.com/Narcooo/inkos" target="_blank" rel="noreferrer">https://github.com/Narcooo/inkos</a></li></ul><hr><h3 id="mojo" tabindex="-1">Mojo <a class="header-anchor" href="#mojo" aria-label="Permalink to “Mojo”">​</a></h3><ul><li><strong>项目名称</strong>: Mojo</li><li><strong>作者</strong>: Modular</li><li><strong>核心功能</strong>: 统一的 AI 开发和部署平台，MAX 框架，Mojo 编程语言（Python 的超集），性能堪比 C/C++，专为 AI 优化</li><li><strong>主要亮点</strong>: <ul><li>Modular 官方项目，质量可靠</li><li>同时提供框架和编程语言</li><li>Mojo 是 Python 的超集，学习成本低</li><li>性能堪比 C/C++</li><li>专为 AI 优化</li><li>完全开源，免费使用</li></ul></li><li><strong>详细介绍</strong>: <a href="/github汇总/编程语言/Mojo-编程语言.html">Mojo 完整文档</a></li><li><strong>GitHub 地址</strong>: <a href="https://github.com/modularml/mojo" target="_blank" rel="noreferrer">https://github.com/modularml/mojo</a></li></ul><hr><h3 id="zig" tabindex="-1">Zig <a class="header-anchor" href="#zig" aria-label="Permalink to “Zig”">​</a></h3><ul><li><strong>项目名称</strong>: Zig</li><li><strong>作者</strong>: Zig Software Foundation</li><li><strong>核心功能</strong>: 通用的编程语言和工具链，语法简洁，编译速度快，简单的交叉编译，可直接调用 C 代码，强大的编译期计算能力</li><li><strong>主要亮点</strong>: <ul><li>现代的系统编程语言</li><li>语法简洁，没有隐藏控制流、隐藏内存分配、预处理器、宏</li><li>编译速度特别快，零依赖</li><li>简单的交叉编译</li><li>可直接调用 C 代码，不需要绑定，也能被 C 代码调用</li><li>强大的编译期计算能力，可在编译期运行代码优化性能</li><li>可选的内存管理，可选择手动管理或使用标准库分配器</li><li>完善的工具链，内置构建系统、打包器、测试框架等</li><li>目前最受关注的现代系统编程语言之一</li></ul></li><li><strong>详细介绍</strong>: <a href="/github汇总/编程语言/Zig-编程语言.html">Zig 完整文档</a></li><li><strong>GitHub 地址</strong>: <a href="https://github.com/ziglang/zig" target="_blank" rel="noreferrer">https://github.com/ziglang/zig</a></li></ul><h2 id="分类特点" tabindex="-1">分类特点 <a class="header-anchor" href="#分类特点" aria-label="Permalink to “分类特点”">​</a></h2><p>本分类编程语言涵盖以下类型：</p><ul><li><strong>系统编程语言</strong> - Go、Zig</li><li><strong>函数式编程语言</strong> - Gleam</li><li><strong>AI 专用语言</strong> - Mojo</li><li><strong>脚本语言变体</strong> - inkos</li></ul><h2 id="语言选择建议" tabindex="-1">语言选择建议 <a class="header-anchor" href="#语言选择建议" aria-label="Permalink to “语言选择建议”">​</a></h2><ol><li><strong>云原生开发</strong> - 推荐使用 Go</li><li><strong>系统编程</strong> - 推荐使用 Zig</li><li><strong>高并发系统</strong> - 推荐使用 Gleam</li><li><strong>AI 开发</strong> - 推荐使用 Mojo</li><li><strong>Lua 生态集成</strong> - 推荐使用 inkos</li></ol><h2 id="贡献建议" tabindex="-1">贡献建议 <a class="header-anchor" href="#贡献建议" aria-label="Permalink to “贡献建议”">​</a></h2><p>如果您发现了优质的编程语言想要分享，欢迎通过以下方式贡献：</p><ul><li>提交 Issue 推荐项目</li><li>提交 PR 添加新资源</li></ul><hr><p><em>开始探索，发现更多编程语言！</em> 💻</p>',28)]))}const c=i(t,[["render",n]]);export{d as __pageData,c as default};
